INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0011$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$11$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 The FY27 budget includes funding to support additional aircraft procurement in FY27, FY28 and FY29 for a total of 12 additional aircraft across the FYDP. It also includes Advanced Procurement (AP) funding for
 the aircraft in FY28 and FY29. The FY27 request also includes remaining requirements to establish E-2D Organic Depot capability in accordance with Title 10 U.S. Code 2464 and government engineering and
 logistics support required to oversee aircraft production still underway.

 The three aircraft in FY 2026 fund the program to 85 E-2D's and aligns with the 19 July 2019 R3B Memo and will be procured on a separate contract at single year pricing and designated as FRP 12.




